   117→/**
   118→ * Handles database errors consistently across all resolvers
   119→ *
   120→ * @param error - The error thrown by the database operation
   121→ * @param config - Configuration for error handling
   122→ * @throws Always throws a user-friendly error
   123→ *
   124→ * @example
   125→ * ```typescript
   126→ * try {
   127→ *   const result = await db.select().from(schema.brands).where(eq(schema.brands.id, id));
   128→ *   return result[0];
   129→ * } catch (error) {
   130→ *   handleDatabaseError(error, { operation: "fetching brand", entityType: "Brand", entityId: id });
   131→ * }
   132→ * ```
   133→ */
   134→export function handleDatabaseError(
   135→  error: unknown,
   136→  config: ErrorHandlerConfig
   137→): never {
   138→  const { operation, entityType, entityId, logError = true } = config;
   139→
   140→  // Log the error for debugging
   141→  if (logError) {
   142→    const context = entityId
   143→      ? `${entityType || "Entity"} ${entityId}`
   144→      : entityType || "resource";
   145→    console.error(`Database error ${operation} (${context}):`, error);
