   130→ *   handleDatabaseError(error, { operation: "fetching brand", entityType: "Brand", entityId: id });
   131→ * }
   132→ * ```
   133→ */
   134→export function handleDatabaseError(
   135→  error: unknown,
   136→  config: ErrorHandlerConfig
   137→): never {
   138→  const { operation, entityType, entityId, logError = true } = config;
   139→
   140→  // Log the error for debugging
   141→  if (logError) {
   142→    const context = entityId
   143→      ? `${entityType || "Entity"} ${entityId}`
   144→      : entityType || "resource";
   145→    console.error(`Database error ${operation} (${context}):`, error);
   146→  }
   147→
   148→  // Classify and create appropriate user message
   149→  const errorType = classifyDatabaseError(error);
   150→  const userMessage = createUserFriendlyMessage(errorType, config);
   151→
   152→  throw new Error(userMessage);
   153→}
